import React, { useEffect, useState } from 'react';
import { getSitios, deleteSitio, createSitio } from './services/culturaService';

function App() {
  const [sitios, setSitios] = useState([]);
  
  // Estado para el formulario
  const [nuevoSitio, setNuevoSitio] = useState({
    nombre: '',
    descripcion: '',
    ubicacion: ''
  });

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    const datos = await getSitios();
    setSitios(datos);
  };

  // Manejar cambios en los inputs
  const handleChange = (e) => {
    setNuevoSitio({
      ...nuevoSitio,
      [e.target.name]: e.target.value
    });
  };

  // Enviar el formulario
  const handleSubmit = async (e) => {
    e.preventDefault();
    await createSitio(nuevoSitio);
    setNuevoSitio({ nombre: '', descripcion: '', ubicacion: '' }); // Limpiar formulario
    cargarDatos(); // Recargar la lista
  };

  const eliminar = async (id) => {
    if(window.confirm('¿Deseas eliminar este sitio cultural?')) {
      await deleteSitio(id);
      cargarDatos();
    }
  };

  return (
    <div style={{ padding: '20px', backgroundColor: '#f4f4f4', minHeight: '100vh', fontFamily: 'Arial' }}>
      <header style={{ textAlign: 'center', marginBottom: '30px' }}>
        <h1 style={{ color: '#d9534f' }}>Cultura La Paz - Panel de Control</h1>
      </header>

      {/* FORMULARIO DE REGISTRO */}
      <div style={{ 
        backgroundColor: 'white', 
        padding: '20px', 
        borderRadius: '10px', 
        maxWidth: '600px', 
        margin: '0 auto 40px auto',
        boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
      }}>
        <h3 style={{ textAlign: 'center' }}>Registrar Nuevo Sitio</h3>
        <form onSubmit={handleSubmit}>
          <input 
            style={{ width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '5px', border: '1px solid #ddd' }}
            name="nombre" 
            placeholder="Nombre del Museo/Sitio" 
            value={nuevoSitio.nombre} 
            onChange={handleChange} 
            required 
          />
          <textarea 
            style={{ width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '5px', border: '1px solid #ddd' }}
            name="descripcion" 
            placeholder="Descripción" 
            value={nuevoSitio.descripcion} 
            onChange={handleChange} 
            required 
          />
          <input 
            style={{ width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '5px', border: '1px solid #ddd' }}
            name="ubicacion" 
            placeholder="Ubicación (Ej: Calle Comercio)" 
            value={nuevoSitio.ubicacion} 
            onChange={handleChange} 
            required 
          />
          <button 
            type="submit" 
            style={{ width: '100%', padding: '10px', backgroundColor: '#5cb85c', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
          >
            Guardar Sitio
          </button>
        </form>
      </div>

      {/* LISTA DE TARJETAS */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', 
        gap: '20px',
        maxWidth: '1200px',
        margin: '0 auto'
      }}>
        {sitios.map(sitio => (
          <div key={sitio._id} style={{ backgroundColor: 'white', padding: '20px', borderRadius: '10px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
            <h3 style={{ color: '#333' }}>{sitio.nombre}</h3>
            <p style={{ color: '#666' }}>{sitio.descripcion}</p>
            <p>📍 <strong>Ubicación:</strong> {sitio.ubicacion}</p>
            <button 
              onClick={() => eliminar(sitio._id)}
              style={{ backgroundColor: '#d9534f', color: 'white', border: 'none', padding: '10px', borderRadius: '5px', cursor: 'pointer', width: '100%' }}
            >
              Eliminar Sitio
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
